solution:
function filterByType<T>(arr: (T | null | undefined)[], type: string): T[] {
  const isOfType = (value: any, typeName: string): value is T => {
    if (value === null || value === undefined) return false;
    if (typeName === 'object') return typeof value === 'object' && !Array.isArray(value);
    return typeof value === typeName;
  };

  return arr.filter(item => isOfType(item, type));
}

