type TrafficLight = { kind: 'red' } | { kind: 'yellow' } | { kind: 'green' };

function assertNever(x: never): never {
  throw new Error('Unhandled variant: ' + JSON.stringify(x));
}

function nextState(light: TrafficLight): TrafficLight {
  switch (light.kind) {
    case 'red':
      return { kind: 'green' };
    case 'yellow':
      return { kind: 'red' };
    case 'green':
      return { kind: 'yellow' };
    default:
      return assertNever(light);
  }
}

