  greet: () => string;
}

type ReadonlyUser = DeepReadonly<User>;
type PartialUser = DeepPartial<User>;

const u: ReadonlyUser = {
  name: 'John',
  address: { street: 'Main', city: 'NYC' },
  tags: ['a'],
  greet: () => 'hi',
};
// u.address.street = 'X'; // Error

const p: PartialUser = { address: { city: 'LA' } }; // Valid

description.en:
Implement a type-safe `EventEmitter` class that uses a generic event map to guarantee at compile time that listeners receive the correct payload for the event they subscribed to.

**Requirements:**
- Generic `EventMap` where each key is an event name and each value is the payload type for that event (use `void` for events with no payload)
- `on<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this` — subscribe, chainable
- `emit<K extends keyof T>(event: K, ...args: T[K] extends void ? [] : [T[K]]): void` — emit, with payload required only for non-void events
- `once<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this` — single-use listener
- `off<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this` — unsubscribe a specific listener
- Attempting to emit or subscribe to an event not present in the map must be a compile-time error
- A listener registered for one event must not type-check against another event's payload

**Function signature:**
typescript
class EventEmitter<T extends Record<string, any>> {
  on<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this;
  once<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this;
  off<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this;
  emit<K extends keyof T>(event: K, ...args: T[K] extends void ? [] : [T[K]]): void;
}


**Example:**
typescript
interface AppEvents {
  'user:login': { userId: string; timestamp: number };
  'user:logout': void;
  'data:update': { data: unknown };
}

const emitter = new EventEmitter<AppEvents>();

emitter.on('user:login', (payload) => {
  console.log(payload.userId); // typed as string
});

emitter.emit('user:login', { userId: '123', timestamp: Date.now() }); // valid
emitter.emit('user:logout'); // valid - no payload arg required
// emitter.emit('user:login'); // Error: payload required
// emitter.emit('nonexistent', {}); // Error: not in EventMap


**Edge cases:**
- `void`-payload events must not require (and must not accept) a second argument to `emit`
- Multiple listeners registered for the same event, all invoked in registration order
- Calling `off` with a listener that was never registered should be a safe no-op
- `once` listeners must be removed automatically after their first invocation, even if `emit` is called again before that

description.ru:
Реализуйте типобезопасный класс `EventEmitter`, который использует обобщённую карту событий, чтобы гарантировать на этапе компиляции, что слушатель получает корректный payload для события, на которое он подписался.

**Требования:**
- Обобщённый `EventMap`, где каждый ключ — имя события, а значение — тип payload для этого события (используйте `void` для событий без payload)
- `on<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this` — подписка, с чейнингом
- `emit<K extends keyof T>(event: K, ...args: T[K] extends void ? [] : [T[K]]): void` — эмит, payload обязателен только для не-void событий
- `once<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this` — одноразовый слушатель
- `off<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this` — отписка конкретного слушателя
- Попытка эмитнуть или подписаться на событие, которого нет в карте, должна быть ошибкой компиляции
- Слушатель, зарегистрированный для одного события, не должен тайпчекаться против payload другого события

**Сигнатура функции:**
typescript
class EventEmitter<T extends Record<string, any>> {
  on<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this;
  once<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this;
  off<K extends keyof T>(event: K, listener: (payload: T[K]) => void): this;
  emit<K extends keyof T>(event: K, ...args: T[K] extends void ? [] : [T[K]]): void;
}


**Пример:**
typescript
interface AppEvents {
  'user:login': { userId: string; timestamp: number };
  'user:logout': void;
  'data:update': { data: unknown };
}

const emitter = new EventEmitter<AppEvents>();

emitter.on('user:login', (payload) => {
  console.log(payload.userId); // типизирован как string
});

emitter.emit('user:login', { userId: '123', timestamp: Date.now() }); // валидно
emitter.emit('user:logout'); // валидно - второй аргумент не нужен
// emitter.emit('user:login'); // Ошибка: нужен payload
// emitter.emit('nonexistent', {}); // Ошибка: нет в EventMap


**Граничные случаи:**
- События с payload типа `void` не должны ни требовать, ни принимать второй аргумент в `emit`
- Несколько слушателей для одного события, все вызываются в порядке регистрации
- Вызов `off` со слушателем, который никогда не регистрировался, должен быть безопасным no-op
- `once`-слушатели должны автоматически удаляться после первого вызова, даже если `emit` вызовут снова до этого

