solution:
interface Token<T> {
  readonly name: string;
  readonly _type?: T;
}

function createToken<T>(name: string): Token<T> {
  return { name };
}

class Container {
  private services = new Map<Token<any>, any>();

  register<T>(token: Token<T>, value: T): void {
    this.services.set(token, value);
  }

  resolve<T>(token: Token<T>): T {
    if (!this.services.has(token)) {
      throw new Error(`No provider registered for token "${token.name}"`);
    }
    return this.services.get(token) as T;
  }
}

// Usage
interface Logger {
  log(message: string): void;
}

const LoggerToken = createToken<Logger>('Logger');
const container = new Container();
container.register(LoggerToken, { log: (msg) => console.log('[LOG]', msg) });

const logger = container.resolve(LoggerToken);
logger.log('hello');

