solution:
type JsonValue = string | number | boolean | null | JsonObject | JsonArray;
type JsonArray = JsonValue[];
type JsonObject = {
  [key: string]: JsonValue;
};

type DeepPartial<T> = T extends object
  ? {
      [P in keyof T]?: DeepPartial<T[P]>;
    }
  : T;

type DeepReadonly<T> = T extends object
  ? {
      readonly [P in keyof T]: DeepReadonly<T[P]>;
    }
  : T;

function isJsonValue(value: unknown): value is JsonValue {
  if (value === null) return true;
  const type = typeof value;
  if (type === 'string' || type === 'number' || type === 'boolean')
    return true;
  if (Array.isArray(value)) {
    return value.every((item) => isJsonValue(item));
  }
  if (type === 'object') {
    return Object.values(value as Record<string, unknown>).every((item) =>
      isJsonValue(item)
    );
  }
  return false;
}

function createValidator<T extends JsonValue>() {
  return (data: unknown): data is T => {
    return isJsonValue(data);
  };
}

// Test cases
type TestType = {
  name: string;
  nested: {
    age: number;
    tags: string[];
  };
};

type TestPartial = DeepPartial<TestType>;
// { name?: string; nested?: { age?: number; tags?: string[] } }
type TestReadonly = DeepReadonly<TestType>;
// { readonly name: string; readonly nested: { readonly age: number; readonly tags: string[] } }

const validator = createValidator<TestType>();
const result = validator({
  name: 'John',
  nested: { age: 30, tags: ['js', 'ts'] },
}); // true

